import sys
input = sys.stdin.readline

def check(h, m, n):
    h = list(h)
    for i in range(n-1, 1, -1):
        if h[i] < m:
            return False
        d_max = (h[i] - m) // 3
        d = d_max
        h[i] -= 3 * d
        h[i-1] += d
        h[i-2] += 2 * d
    return all(x >= m for x in h)

def solve():
    n = int(input())
    h = list(map(int, input().split()))
    lo, hi = 0, sum(h) // n
    while lo < hi:
        mid = (lo + hi + 1) // 2
        if check(h, mid, n):
            lo = mid
        else:
            hi = mid - 1
    print(lo)

t = int(input())
for _ in range(t):
    solve()
